    case 'any':
      return yield* anySchemaParser(schema, unextendedInput, nextOpts)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return yield* primitiveSchemaParser(schema, unextendedInput, nextOpts)
    case 'set':
